extension.valueString:
/* End of HIV-inconclusive */

/*
@dataElement: HIV.B.DE115 - HIV status
@activity: HIV.B7 Test for HIV using testing algorithm
@description: HIV status reported after applying the national HIV testing algorithm. No single HIV test can provide an HIV-positive diagnosis.
*/
define "HIV Status Observation":
  [Observation: Concepts."HIV status"] O
    where O.status in { 'final', 'amended', 'corrected' }

/* End of HIV test result B.DE111 */

/*
@dataElement: HIV.B.DE115 - HIV status
@activity: HIV.B7 Test for HIV using testing algorithm
@description: HIV status reported after applying the national HIV testing algorithm. No single HIV test can provide an HIV-positive diagnosis.
*/
define "HIV Status Observation":
  Elements."HIV Status Observation" O
    where O.encounter.references(EncounterId)

/*
  @input: "HIV status negative or unknown"
  @pseudocode: "HIV status" IN 'HIV-negative', 'Unknown'
  */
define "HIV status negative or unknown":
  exists(Elements."HIV Status Observation" S
    where S.value ~ Concepts."HIV-negative"
       or S.value ~ Concepts."Unknown")

/* End of Extrapulmonary TB D.DE937 */

/*
@dataElement: HIV.D.DE939 - TB diagnosis result
@activity: HIV.D8 Capture or update client history
@description: Final result of the TB investigation (bacteriological and/or clinical)
*/

define "TB diagnosis result":
  [Observation: Concepts."TB diagnosis result"] O
    where O.status in { 'final', 'amended', 'corrected' }

/* End of Extrapulmonary TB D.DE937 */

/*
@dataElement: HIV.D.DE939 - TB diagnosis result
@activity: HIV.D8 Capture or update client history
@description: Final result of the TB investigation (bacteriological and/or clinical)
*/
define "TB diagnosis result":
  Elements."TB diagnosis result" O
    where O.encounter.references(EncounterId)
      or O.effective.toInterval() starts on or before Today

/*
  @input: "TB diagnosis result is diagnosed TB"
  @pseudocode: "Currently pregnant"=True
  */
define "TB diagnosis result is diagnosed TB":
  exists(Elements."TB diagnosis result" O
    where O.value ~ Concepts."Diagnosed TB")

define "Risk factors, comorbidities and coinfections signs and symptoms Observation":
  [Observation: Concepts."Risk factors, comorbidities and coinfections signs and symptoms"] O
    where O.status in { 'final', 'amended', 'corrected' }

/*
  @input: "Presumptive TB"
  @pseudocode: "Presumptive TB"=True
  */
define "Presumptive TB":
  exists(Elements."Presumptive TB D.DE282 Observation" O
    where O.value is true)

/*
  @input: "HIV burden of setting is high HIV burden setting"
  @pseudocode: "HIV burden of the setting"='High HIV burden setting'
  */
define "HIV burden of setting is high HIV burden setting":
  Config."HIV burden of setting" ~ Concepts."High HIV burden setting"

define "Pregnancy Status Observation":
  [Observation: Concepts."Pregnancy status"] O
    where O.status in { 'final', 'amended', 'corrected' }

/*
  @input: "Currently pregnant"
  @pseudocode: "Currently pregnant"=True
  */
define "Currently pregnant":
  exists(WElm."Pregnant Observation")

/*
 @output: "Schedule an HIV test, syphilis test, hepatitis B test as early as possible during this pregnancy"
 @pseudocode: N/A
 */
define "Schedule an HIV test, syphilis test, hepatitis B test as early as possible during this pregnancy":
  "Pregnant in high HIV burden setting"

/*
  @input: "HIV burden of setting is low HIV burden setting"
  @pseudocode: "HIV burden of the setting"='Low HIV burden setting'
  */
define "HIV burden of setting is low HIV burden setting":
  Config."HIV burden of setting" ~ Concepts."Low HIV burden setting"

/* End of Key population member B.DE49 */

/*
@dataElement: HIV.B.DE50 - Key population member type
@activity: HIV.B6 Capture or update client history
@description: The type of key population that the client is included in
*/
define "Key population member type Observation":
  [Observation: Concepts."Key population member - HIV.B.DE49"] O
    where O.status in { 'final', 'amended', 'corrected' }
    and exists(O.category OC where OC ~ ConceptsCustom."social-history")

/* End of Key population member B.DE49 */

/*
@dataElement: HIV.B.DE50 - Key population member type
@activity: HIV.B6 Capture or update client history
@description: The type of key population that the client is included in
*/
define "Key population member type Observation":
  Elements."Key population member type Observation" O
    where O.encounter.references(EncounterId)
      or O.effective.toInterval() starts on or before Today

/* End of Unknown B.DE36 */

/*
@dataElement: HIV.B.DE49 - Key population member
@activity: HIV.B6 Capture or update client history
@description: Client is a member of a key population that has an increased risk of HIV
*/
define "Is Key population member":
  exists(
    "Key population member type Observation" O
  )

/*
  @input: "Key population member"
  @pseudocode: "Key population member" = TRUE
  */
define "Key population member":
  Elements."Is Key population member"

define "Partner HIV status reported Observation":
  [Observation: Concepts."Partner HIV status reported"] O
    where O.status in { 'final', 'amended', 'corrected' }

/* End of Currently pregnant B.DE29 */

/*
@dataElement: HIV.B.DE33 - Partner HIV status reported
@activity: HIV.B6 Capture or update client history
@description: The HIV status of the client's partner.
*/
define "Partner HIV status reported Observation":
  Elements."Partner HIV status reported Observation" O
    where O.encounter.references(EncounterId)

/*
  @input: "Partner HIV reported positive"
  @pseudocode: "Partner HIV status (reported)"='HIV-positive'
  */
define "Partner HIV positive":
  exists(Elements."Partner HIV status reported Observation" O
    where O.value ~ Concepts."HIV-positive")

/* End of Rash */

/*
@dataElement: HIV.C.DE55 - Sex partners HIV treatment status
@activity: HIV.C3 Capture or update client history
@description: Treatment adherence of client's sex partner for partners that are HIV-positive
*/
// TODO: Replace placeholder with relevant CQL logic
define "Sex partners HIV treatment status":
  [Observation: Concepts."Sex partners HIV treatment status"] O
    where O.status in { 'final', 'amended', 'corrected' }

/* End of Rash */

/*
@dataElement: HIV.C.DE55 - Sex partners HIV treatment status
@activity: HIV.C3 Capture or update client history
@description: Treatment adherence of client's sex partner for partners that are HIV-positive
*/
define "Sex partners HIV treatment status":
  Elements."Sex partners HIV treatment status" O
    where O.encounter.references(EncounterId)

/*
  @input: "Sex partner's HIV treatment status is partner not virally suppressed"
  @pseudocode: "Sex partner's HIV treatment status"='Partner is not virally suppressed'
  */
define "Sex partner's HIV treatment status is partner not virally suppressed":
  exists(Elements."Sex partners HIV treatment status" O
    where O.value ~ Concepts."Partner is not virally suppressed")

/* End of Other reason for stopping ART H.DE80 */

/*
@dataElement: HIV.PRV.DE1 - At elevated risk for HIV acquisition
@activity: HIV.B6 Capture or update client history
@description: Client is at elevated risk for HIV acquisition, defined according to country/programme context
*/

define "At elevated risk for HIV acquisition PRV.DE1":
  [Observation] O
    where O.status in { 'final', 'amended', 'corrected' }
    and exists(O.category OC where OC ~ ConceptsCustom."social-history")
    and O.code ~ Concepts."At elevated risk for HIV acquisition - HIV.PRV.DE1"

/* End of On ART H.DE47 */

/*
@dataElement: HIV.PRV.DE1 - At elevated risk for HIV acquisition
@activity: HIV.B6 Capture or update client history
@description: Client is at elevated risk for HIV acquisition, defined according to country/programme context
*/
define "At elevated risk for HIV acquisition PRV.DE1 Observation":
  Elements."At elevated risk for HIV acquisition PRV.DE1" O
    where O.encounter.references(EncounterId)
      or O.effective.toInterval() starts on or before Today

/*
  @input: "At elevated risk for HIV acquisition"
  @pseudocode: "At elevated risk for HIV acquisition"=True
  */
define "At elevated risk for HIV acquisition":
  exists(Elements."At elevated risk for HIV acquisition PRV.DE1 Observation" O
    where O.value is true)

/* End of Date/time of suspected exposure to HIV C.DE9 */

/*
@dataElement: HIV.C.DE10 - Currently on PrEP
@activity: HIV.C3 Capture or update client history
@description: The client is currently taking PrEP. Oral pre-exposure prophylaxis (PrEP) of HIV is the use of ARV drugs by people who are not infected with HIV to block the acquisition of HIV.
*/

/*@triggeredBy Encounter with location = community level testing*/

define "Currently on PrEP":
  [MedicationStatement] MS
    where MS.status = 'completed'
    and exists(MS.reasonCode C where C ~ Concepts."Currently on PrEP")
    and MS.medication ~ Concepts."PrEP for HIV prevention"

/* End of Date/time of suspected exposure to HIV C.DE9 */

/*
@dataElement: HIV.C.DE10 - Currently on PrEP
@activity: HIV.C3 Capture or update client history
@description: The client is currently taking PrEP. Oral pre-exposure prophylaxis (PrEP) of HIV is the use of ARV drugs by people who are not infected with HIV to block the acquisition of HIV.
*/
define "Currently on PrEP":
  Elements."Currently on PrEP" O
    where O.effective.toInterval() starts on or before Today

/*
  @input: "Currently on PrEP"
  @pseudocode: "Currently on PrEP"=True
  */
define "Currently on PrEP":
  exists(Elements."Currently on PrEP")

/*
 @output: "Schedule quarterly retesting for PrEP users"
 @pseudocode: N/A
 */
define "Schedule quarterly retesting for PrEP users":
  "HIV status negative or unknown" and "Currently on PrEP"

/*
@description: Returns true if the given reference is to the given resourceId
@comment: Returns true if the `resourceId` parameter exactly equals the tail of the given reference.
NOTE: This function assumes resources from the same source server.
*/
define fluent function references(reference FHIR.Reference, resourceId String):
  resourceId = Last(Split(reference.reference, '/'))
